# This file is hand-written and intentionally NOT generated by Fern.
# It is listed in .fernignore so regeneration never clobbers it.
#
# Prefix-routing wrapper around the Fern-generated client.
#
# The base URL is derived automatically from the API key's prefix so that
# partners only need to pass their key:
#
#   * key starting "live_"    -> Production (https://api.voltaria.io)
#   * key starting "sandbox_" -> Sandbox    (https://api.sandbox.voltaria.io)
#   * unknown / empty prefix  -> raises InvalidApiKeyError
#
# An explicitly passed `environment` or `base_url` ALWAYS overrides prefix
# routing (used for staging and tests).

from __future__ import annotations

import typing

from ._generated.client import AsyncVoltaria as _GeneratedAsyncVoltaria
from ._generated.client import Voltaria as _GeneratedVoltaria
from ._generated.environment import VoltariaEnvironment


class InvalidApiKeyError(ValueError):
    """Raised when an API key does not carry a recognised environment prefix.

    A valid key must start with ``live_`` (production) or ``sandbox_``
    (sandbox). This is raised eagerly at client construction time so that
    misconfigured keys fail fast rather than producing confusing 401s later.
    """

    def __init__(self, api_key: str | None) -> None:
        self.api_key = api_key
        super().__init__(
            "Could not resolve an environment from the provided API key. "
            'Keys must start with "live_" (production) or "sandbox_" (sandbox). '
            "Alternatively, pass an explicit `environment` or `base_url`."
        )


def resolve_environment(
    api_key: str | None,
    *,
    environment: VoltariaEnvironment | None = None,
    base_url: str | None = None,
) -> VoltariaEnvironment | None:
    """Resolve the environment to use for the client.

    Mirrors the TypeScript wrapper's ``resolve_environment`` exactly:

    * an explicit ``environment`` wins outright;
    * an explicit ``base_url`` wins, and we return ``None`` so the generated
      client uses the base url instead of an environment;
    * otherwise we route on the key prefix;
    * an unrecognised / empty prefix raises :class:`InvalidApiKeyError`.
    """
    if environment is not None:
        return environment
    if base_url is not None:
        return None
    if api_key and api_key.startswith("live_"):
        return VoltariaEnvironment.PRODUCTION
    if api_key and api_key.startswith("sandbox_"):
        return VoltariaEnvironment.SANDBOX
    raise InvalidApiKeyError(api_key)


class Voltaria(_GeneratedVoltaria):
    """Prefix-routing synchronous Voltaria client.

    Stripe-style ergonomics: pass your API key as the only required argument
    and the correct environment is selected from its prefix::

        from voltaria import Voltaria

        client = Voltaria("live_...")      # -> production
        client = Voltaria("sandbox_...")   # -> sandbox

    All other generated options are passed straight through. Supplying an
    explicit ``environment`` or ``base_url`` overrides prefix routing.
    """

    def __init__(
        self,
        api_key: str,
        *,
        base_url: str | None = None,
        environment: VoltariaEnvironment | None = None,
        **kwargs: typing.Any,
    ) -> None:
        resolved = resolve_environment(
            api_key, environment=environment, base_url=base_url
        )
        super().__init__(
            token=api_key,
            base_url=base_url,
            # The generated client defaults environment to SANDBOX; only pass a
            # concrete value so base_url can take over when environment is None.
            **({"environment": resolved} if resolved is not None else {}),
            **kwargs,
        )


class AsyncVoltaria(_GeneratedAsyncVoltaria):
    """Prefix-routing asynchronous Voltaria client.

    Async counterpart to :class:`Voltaria`; see that class for behaviour.
    """

    def __init__(
        self,
        api_key: str,
        *,
        base_url: str | None = None,
        environment: VoltariaEnvironment | None = None,
        **kwargs: typing.Any,
    ) -> None:
        resolved = resolve_environment(
            api_key, environment=environment, base_url=base_url
        )
        super().__init__(
            token=api_key,
            base_url=base_url,
            **({"environment": resolved} if resolved is not None else {}),
            **kwargs,
        )


__all__ = [
    "AsyncVoltaria",
    "InvalidApiKeyError",
    "Voltaria",
    "resolve_environment",
]
